+/* ── Pixel-art SVG renderer ──────────────────────────────────
+   pixels: Array of [row, col, color]
+   Each cell is `sz` × `sz` pixels on a w × h canvas.
+*/
+function makeSVG(pixels, bg = '#0d0d0d', w = 128, h = 80, sz = 8) {
+    const rects = pixels
+        .map(([r, c, col]) =>
+            `<rect x="${c * sz}" y="${r * sz}" width="${sz}" height="${sz}" fill="${col}"/>`)
+        .join('');
+    return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg" `
+         + `class="card-thumb" style="image-rendering:pixelated">`
+         + `<rect width="${w}" height="${h}" fill="${bg}"/>${rects}</svg>`;
+}
+
+/* ── Pixel-art data  (16 cols × 10 rows @ 8 px each = 128 × 80) ── */
