+    // Vertical descent: col 12, rows 2-6
+    ...[2,3,4,5,6].map(r => [r, 12, G]),
+    // Head (brighter): row 7, col 12 — facing down
+    [7, 12, H],
+    // Food dots scattered in the open field
+    [3, 4, F],
+    [5, 8, F],
+];
+
+// Tetris — colourful stacked blocks + a falling T-piece
