+    [0, 6, TC], [0, 7, TC], [0, 8, TC],
+    [1, 7, TC],
+    // Stack row 6 — full row (14 cols), pairs of contrasting colours
+    [6,0,TR],[6,1,TR],[6,2,TY],[6,3,TY],[6,4,TG],[6,5,TG],
+    [6,6,TC],[6,7,TC],[6,8,TM],[6,9,TM],[6,10,TR],[6,11,TR],
+    [6,12,TY],[6,13,TY],
+    // Stack row 7 — 11 cols
+    [7,0,TY],[7,1,TY],[7,2,TG],[7,3,TG],[7,4,TC],[7,5,TC],
+    [7,6,TR],[7,7,TR],[7,8,TM],[7,9,TM],[7,10,TY],
+    // Stack row 8 — 7 cols
+    [8,0,TG],[8,1,TG],[8,2,TM],[8,3,TM],[8,4,TY],[8,5,TY],[8,6,TC],
+    // Stack row 9 — 4 cols
+    [9,0,TR],[9,1,TR],[9,2,TC],[9,3,TC],
+];
+
+// Breakout — brick rows + ball + paddle
