+    ...[0,1,2,3,5,6,7,8,9,11,12,13].map(c => [1, c, BO]),
+    // Yellow brick row 2: several bricks missing — mid-game feel
+    ...[0,1,3,5,6,8,9,11,13].map(c => [2, c, BY]),
+    // Ball: row 5, col 7 (centre-ish, heading up)
+    [5, 7, BW],
+    // Paddle: row 8, cols 3-10 (wide white bar)
+    ...[3,4,5,6,7,8,9,10].map(c => [8, c, BW]),
+];
+
+// Pong — two paddles, dashed centre net, ball
