+    ...[3,4,5,6].map(r => [r, 1, PW]),
+    // Right paddle: col 14, rows 4-7
+    ...[4,5,6,7].map(r => [r, 14, PW]),
+    // Centre net: col 8, every other row (dashed)
+    ...[0,2,4,6,8].map(r => [r, 8, PG]),
+    // Ball: row 5, col 5
+    [5, 5, PW],
+];
+
